// AUIPC at varied non-zero PCs.  AUIPC computes rd = pc + (imm_upper << 12),
// so vectors that pin pc = 0 (as in `AUIPC_VECTORS` above) cannot distinguish
// AUIPC from LUI.  Tuple: (rd, imm_upper_20bit, initial_pc, rd_val).
//
// PC values are bounded so the bytecode array fits comfortably in memory:
// the test allocator rounds bytecode size up to (pc/4 + 1).next_power_of_two(),
// so keep PCs <= ~0x4000 (16 KiB code).
pub const AUIPC_WITH_PC_VECTORS: &[(u8, u32, u32, u32)] = &[
    (3, 0x00002, 0x00001000, 0x00003000),  // basic mid-page
    (1, 0x00000, 0x00000004, 0x00000004),  // imm = 0, rd should be pc itself
    (5, 0x00001, 0x00000FFC, 0x00001FFC),  // PC just below 4 KiB boundary
    (10, 0x12345, 0x00002000, 0x12347000), // generic non-trivial
    (31, 0xFFFFF, 0x00000004, 0xFFFFF004), // max imm, low PC
    (0, 0x01234, 0x00000100, 0x00000000),  // rd=x0 → result discarded, must read 0
    (15, 0x80000, 0x00004000, 0x80004000), // sign bit of imm set
    (7, 0x00100, 0x00000400, 0x00100400),  // mid imm, mid PC
];

