pub const JAL_VECTORS: &[(u8, u32, u32)] = &[
    // Smallest forward, varied rd
    (1, 0x00000004, 0x00000000),
    (2, 0x00000008, 0x00000000),
    (3, 0x0000000C, 0x00000000),
    (5, 0x00000010, 0x00000004),
    (7, 0x00000020, 0x00000000),
    (11, 0x00000040, 0x00000000),
    (15, 0x00000080, 0x00000000),
    (19, 0x00000100, 0x00000000),
    (23, 0x00000400, 0x00000000),
    // imm[11] set (encoded at bit 20; B/J-style scattering boundary)
    (27, 0x00000800, 0x00000000),
    (17, 0x00000804, 0x00000000),
    // imm[19:12] populated
    (31, 0x00001000, 0x00000000),
    (1, 0x00010000, 0x00000000),
    (2, 0x00080000, 0x00000000),
    (3, 0x000ABCDC, 0x00000000),
    // Largest positive (signed 21-bit max, word-aligned)
    (13, 0x000FFFFC, 0x00000000),
    // Backward, varied magnitude
    (5, 0xFFFFFFFC, 0x00000100),
    (7, 0xFFFFFFF8, 0x00000100),
    (9, 0xFFFFFFC0, 0x00000100),
    (11, 0xFFFFF000, 0x00010000),
    (13, 0xFFFFC000, 0x00010000),
    (15, 0xFFFC0000, 0x00100000),
    // Most negative (-1MiB) and most-negative + 4
    (1, 0xFFF00000, 0x00200000),
    (1, 0xFFF00004, 0x00200000),
    // `j` pseudo-op (rd = x0): no link write
    (0, 0x00000008, 0x00000000),
    (0, 0xFFFFFFFC, 0x00000100),
    // High initial_pc (upper-limb arithmetic)
    (1, 0x00000004, 0xCAFE0000),
    (5, 0x00000010, 0xDEADBEEC),
];

